Here's the complete sorting-algorithm visualizer:

```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Sorting Visualizer</title>
<style>
  :root {
    --bg: #0d1117;
    --panel: #161b22;
    --accent: #58a6ff;
    --bar: #388bfd;
    --bar-active: #f778ba;
    --bar-sorted: #3fb950;
    --text: #c9d1d9;
    --border: #30363d;
  }
  * { box-sizing: border-box; }
  body {
    margin: 0;
    background: var(--bg);
    color: var(--text);
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
    min-height: 100vh;
    display: flex;
    flex-direction: column;
    align-items: center;
  }
  h1 {
    font-weight: 600;
    font-size: 1.4rem;
    margin: 24px 0 16px;
    color: var(--text);
  }
  #controls {
    display: flex;
    gap: 12px;
    margin-bottom: 20px;
  }
  button {
    background: var(--panel);
    color: var(--text);
    border: 1px solid var(--border);
    border-radius: 6px;
    padding: 8px 18px;
    font-size: 0.9rem;
    cursor: pointer;
    transition: background 0.15s, border-color 0.15s;
  }
  button:hover {
    background: #21262d;
    border-color: var(--accent);
  }
  button:active { transform: translateY(1px); }
  button:disabled {
    opacity: 0.5;
    cursor: not-allowed;
  }
  #sort {
    background: var(--accent);
    color: #0d1117;
    border-color: var(--accent);
    font-weight: 600;
  }
  #sort:hover { background: #79b8ff; }
  #bars {
    display: flex;
    align-items: flex-end;
    gap: 2px;
    height: 60vh;
    width: 90vw;
    max-width: 1100px;
    padding: 12px;
    background: var(--panel);
    border: 1px solid var(--border);
    border-radius: 10px;
  }
  .bar {
    flex: 1 1 auto;
    background: var(--bar);
    border-radius: 2px 2px 0 0;
    transition: height 0.06s linear, background 0.06s linear;
    min-width: 1px;
  }
  .bar.active { background: var(--bar-active); }
  .bar.sorted { background: var(--bar-sorted); }
  footer {
    margin: 18px 0;
    font-size: 0.8rem;
    color: #6e7681;
  }
</style>
</head>
<body>
  <h1>Sorting Visualizer</h1>
  <div id="controls">
    <button id="sort">Sort</button>
    <button id="shuffle">Shuffle</button>
    <button id="reset">Reset</button>
  </div>
  <div id="bars"></div>
  <footer>Insertion sort · ascending · one step at a time</footer>

<script>
(function () {
  "use strict";

  const N = 60;
  const MIN_VAL = 5;
  const MAX_VAL = 100;

  const barsEl = document.getElementById("bars");
  const sortBtn = document.getElementById("sort");
  const shuffleBtn = document.getElementById("shuffle");
  const resetBtn = document.getElementById("reset");

  let arr = [];
  let initialArr = [];      // snapshot for reset
  let barEls = [];

  // Insertion-sort state machine (driven one step at a time)
  let i = 1;                // current element being inserted
  let j = 0;                // scan pointer
  let done = false;
  let animating = false;
  let rafId = null;

  function makeArray(n) {
    const a = [];
    for (let k = 0; k < n; k++) {
      a.push(MIN_VAL + Math.floor(Math.random() * (MAX_VAL - MIN_VAL + 1)));
    }
    return a;
  }

  function resetSortState() {
    i = 1;
    j = 0;
    done = arr.length <= 1;
  }

  function render() {
    barsEl.innerHTML = "";
    barEls = [];
    const max = Math.max(1, ...arr);
    for (let k = 0; k < arr.length; k++) {
      const bar = document.createElement("div");
      bar.className = "bar";
      bar.style.height = (arr[k] / max * 100) + "%";
      barsEl.appendChild(bar);
      barEls.push(bar);
    }
  }

  function updateHeights() {
    const max = Math.max(1, ...arr);
    for (let k = 0; k < arr.length; k++) {
      if (barEls[k]) barEls[k].style.height = (arr[k] / max * 100) + "%";
    }
  }

  function clearHighlights() {
    for (const b of barEls) b.classList.remove("active", "sorted");
  }

  function highlight() {
    clearHighlights();
    if (done) {
      for (const b of barEls) b.classList.add("sorted");
      return;
    }
    // mark the portion already sorted
    for (let k = 0; k < i && k < barEls.length; k++) {
      // sorted-so-far region gets a subtle marker only on the boundary
    }
    if (barEls[j]) barEls[j].classList.add("active");
    if (barEls[j + 1]) barEls[j + 1].classList.add("active");
  }

  // One step of insertion sort. Returns true when fully sorted.
  function sortStep() {
    if (done) return true;

    if (i >= arr.length) {
      done = true;
      return true;
    }

    // Insertion of element at index i: shift leftwards while out of order.
    if (j >= 0 && arr[j] > arr[j + 1]) {
      const tmp = arr[j];
      arr[j] = arr[j + 1];
      arr[j + 1] = tmp;
      j--;
    } else {
      // element placed; move to next
      i++;
      j = i - 1;
      if (i >= arr.length) {
        done = true;
        return true;
      }
    }
    return false;
  }

  function isSorted() {
    for (let k = 1; k < arr.length; k++) {
      if (arr[k - 1] > arr[k]) return false;
    }
    return true;
  }

  function stopAnimation() {
    animating = false;
    if (rafId !== null) {
      cancelAnimationFrame(rafId);
      rafId = null;
    }
    setButtonsEnabled(true);
  }

  function setButtonsEnabled(enabled) {
    sortBtn.disabled = !enabled;
    shuffleBtn.disabled = !enabled;
    resetBtn.disabled = !enabled;
  }

  function animate() {
    if (!animating) return;
    // a few steps per frame so it finishes at a pleasant pace
    const stepsPerFrame = Math.max(1, Math.round(arr.length / 40));
    let finished = false;
    for (let s = 0; s < stepsPerFrame; s++) {
      if (sortStep()) { finished = true; break; }
    }
    updateHeights();
    highlight();
    if (finished) {
      stopAnimation();
      highlight();
      return;
    }
    rafId = requestAnimationFrame(animate);
  }

  function startSort() {
    if (animating) return;
    if (done) return;
    animating = true;
    setButtonsEnabled(false);
    sortBtn.disabled = true;
    rafId = requestAnimationFrame(animate);
  }

  function shuffle() {
    stopAnimation();
    // Fisher-Yates on the current array
    for (let k = arr.length - 1; k > 0; k--) {
      const r = Math.floor(Math.random() * (k + 1));
      const t = arr[k]; arr[k] = arr[r]; arr[r] = t;
    }
    resetSortState();
    render();
  }

  function reset() {
    stopAnimation();
    arr = initialArr.slice();
    resetSortState();
    render();
  }

  // Public API for grading
  window.viz = {
    array: function () { return arr.slice(); },
    setArray: function (a) {
      arr = Array.prototype.slice.call(a).map(Number);
      initialArr = arr.slice();
      resetSortState();
      render();
    },
    sortStep: function () { return sortStep(); },
    sorted: function () { return isSorted(); },
  };

  // Wire up controls
  sortBtn.addEventListener("click", startSort);
  shuffleBtn.addEventListener("click", shuffle);
  resetBtn.addEventListener("click", reset);

  // Init
  arr = makeArray(N);
  initialArr = arr.slice();
  resetSortState();
  render();
})();
</script>
</body>
</html>
```
